def search_hadith_by_patterns(patterns, and_all=True, max_hits=50):
    results=[]
    for idx, rec in enumerate(hadith):
        text = rec.get("hadithTxt") or rec.get("Matn") or ""
        ntext=normalize(text)
        if and_all:
            ok=all(p in ntext for p in patterns)
        else:
            ok=any(p in ntext for p in patterns)
        if ok:
            results.append((idx, text))
            if len(results)>=max_hits:
                break
    return results

