def lcs_length(a,b):
    a=normalize(a); b=normalize(b)
    n,m=len(a),len(b)
    dp=[0]*(m+1)
    for ch in a:
        prev=0
        for j in range(1,m+1):
            tmp=dp[j]
            if ch==b[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j],dp[j-1])
            prev=tmp
    return dp[m]

def lcs_norm(a,b):
    a=normalize(a); b=normalize(b)
    lcs=lcs_length(a,b)
    # normalized by max length (common approach)
    return lcs / max(len(a), len(b))

